</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListAddAtHead(obj, 7);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListAddAtHead(obj, 3);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListAddAtHead(obj, 2);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListAddAtHead(obj, 5);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListAddAtTail(obj, 5);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//int a = myLinkedListGet(obj, 5);printf(&#34;get: %d\n&#34;, a);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListDeleteAtIndex(obj, 6);
</span><span style="color:#75715e"></span> <span style="color:#75715e">//myLinkedListDeleteAtIndex(obj, 4);
</span><span style="color:#75715e"></span> printf(<span style="color:#e6db74">&#34;length: %d</span><span style="color:#ae81ff">\n</span><span style="color:#e6db74">&#34;</span>, obj <span style="color:#f92672">-&gt;</span> length);
printf(<span style="color:#e6db74">&#34;head: %d, tail: %d</span><span style="color:#ae81ff">\n</span><span style="color:#e6db74">&#34;</span>, obj <span style="color:#f92672">-&gt;</span> head <span style="color:#f92672">-&gt;</span> val, obj <span style="color:#f92672">-&gt;</span> tail <span style="color:#f92672">-&gt;</span> val);
printMyLinkedList(obj);
myLinkedListFree(obj);
<span style="color:#66d9ef">return</span> <span style="color:#ae81ff">0</span>;
}
